    &lt;script&gt;
      function changeLanguage(lang) {
          if (!LANG_URLS[lang]) {
              console.error(&#039;Language URL not found for:&#039;, lang);
              return;
          }

          const $switcher = $(&#039;.language-switcher .nav-link&#039;);
          const originalHtml = $switcher.html();
          $switcher.html(&#039;&lt;i class=&quot;fas fa-spinner fa-spin mr-1&quot;&gt;&lt;/i&gt; Loading...&#039;);

          $.ajax({
              url: LANG_URLS[lang],
              type: &#039;GET&#039;,
              dataType: &#039;json&#039;,
              success: function(response) {
                  if (response.success) {
                      if (typeof toastr !== &#039;undefined&#039;) {
                          toastr.success(response.message);
                      }
                      setTimeout(() =&gt; {
                          window.location.reload();
                      }, 500);
                  } else {
                      throw new Error(response.message);
                  }
              },
              error: function(xhr, status, error) {
                  console.error(&#039;Language change failed:&#039;, error);
                  $switcher.html(originalHtml);
                  if (typeof toastr !== &#039;undefined&#039;) {
                      toastr.error(&#039;Language changed successfully&#039;);
                  }
              }
          });
      }

      $(document).ready(function(){
          $(&#039;.current-language&#039;).text(CURRENT_LANG.toUpperCase());
      });
    &lt;/script&gt;
